class Solution:
    def numberOfAlternatingGroups(self, colors) -> int:
        n = len(colors)
        count = 0
        for i in range(n):
            prev = colors[(i - 1) % n]
            nxt = colors[(i + 1) % n]
            if colors[i] != prev and colors[i] != nxt:
                count += 1
        return count

