var numberOfAlternatingGroups = function(colors) {
    const n = colors.length;
    let count = 0;
    for (let i = 0; i < n; i++) {
        if (colors[i] !== colors[(i - 1 + n) % n] && colors[i] !== colors[(i + 1) % n]) {
            count++;
        }
    }
    return count;
};
